  width: 100%; padding: 0.55rem 0.9rem; border: 1.5px solid var(--border);
  border-radius: 9px; font-size: 0.85rem; color: var(--text); outline: none;
  font-family: inherit; background: var(--bg); transition: border 0.15s;
}
.form-input:focus { border-color: var(--primary); background: #fff; }
.drop-zone {
  border: 2px dashed var(--border); border-radius: 12px; padding: 2rem 1rem;
  text-align: center; cursor: pointer; transition: all 0.2s; background: var(--bg);
}
.drop-zone:hover, .drop-zone.drag-over { border-color: var(--primary); background: #f0f5ff; }
.drop-zone-icon { font-size: 2rem; margin-bottom: 0.5rem; }
.drop-zone-text { font-size: 0.82rem; color: var(--text-muted); }
.drop-zone-text b { color: var(--primary); }
.drop-zone input[type=file] { display: none; }
.modal-actions { display: flex; gap: 0.75rem; justify-content: flex-end; margin-top: 1.4rem; }
.modal-cancel {
  padding: 0.55rem 1.2rem; border-radius: 9px; border: 1.5px solid var(--border);
  background: none; font-size: 0.85rem; color: var(--text-muted); cursor: pointer; font-family: inherit;
}
.modal-submit {
  padding: 0.55rem 1.4rem; border-radius: 9px; border: none;
  background: var(--primary); color: #fff; font-size: 0.85rem; font-weight: 600;
  cursor: pointer; font-family: inherit; transition: background 0.15s;
}
.modal-submit:hover { background: #3574e2; }
.upload-progress { margin-top: 1rem; display: none; }
.progress-bar-wrap { height: 6px; background: var(--bg); border-radius: 99px; overflow: hidden; margin-bottom: 0.4rem; }
.progress-bar-fill { height: 100%; background: var(--primary); border-radius: 99px; width: 0%; transition: width 0.3s; }
.progress-label { font-size: 0.75rem; color: var(--text-muted); }
.upload-success { display: none; text-align: center; padding: 1rem 0; }
.upload-success .success-icon { font-size: 2.5rem; margin-bottom: 0.5rem; }
.upload-success .success-msg { font-size: 0.9rem; font-weight: 700; color: var(--success); }
.upload-success .success-sub { font-size: 0.78rem; color: var(--text-muted); margin-top: 0.25rem; }

