/* ── Date Picker Shared Functions ── */
function toggleDP(dropId, e) {
  if(e) e.stopPropagation();
  document.querySelectorAll('.date-picker-drop.open').forEach(d => { if(d.id!==dropId) d.classList.remove('open'); });
  document.getElementById(dropId).classList.toggle('open');
}
function closeDP(dropId) { document.getElementById(dropId).classList.remove('open'); }
function fmtDate(d) {
  const dt = new Date(d + 'T00:00:00');
  return dt.toLocaleDateString('en-GB', {day:'numeric', month:'short', year:'numeric'});
}
function applyDP(fromId, toId, labelId, dropId) {
  const from = document.getElementById(fromId).value;
  const to = document.getElementById(toId).value;
  if(!from || !to) { alert('Please select both dates'); return; }
  document.getElementById(labelId).textContent = '📅 ' + fmtDate(from) + ' – ' + fmtDate(to);
  closeDP(dropId);
}
function setPreset(fromId, toId, labelId, dropId, days) {
