  const from = new Date(to); from.setDate(from.getDate() - days + 1);
  const toStr = to.toISOString().slice(0,10);
  const fromStr = from.toISOString().slice(0,10);
  document.getElementById(fromId).value = fromStr;
  document.getElementById(toId).value = toStr;
  document.querySelectorAll('.dp-preset').forEach(b => b.classList.remove('active'));
  applyDP(fromId, toId, labelId, dropId);
}
document.addEventListener('click', function(e) {
