// ── Pagination ──
const PAGE_SIZE = 7;
let currentPg = 1;

function getPagedUsers() {
  const start = (currentPg - 1) * PAGE_SIZE;
  return filteredUsers.slice(start, start + PAGE_SIZE);
}

const _origRender = renderTable;
function renderTable() {
  const tbody = document.getElementById('userTableBody');
  const pagedUsers = getPagedUsers();
  if (pagedUsers.length === 0 && filteredUsers.length === 0) {
    tbody.innerHTML = `<tr><td colspan="7" style="text-align:center;padding:3rem;color:var(--text-dim);">No users found</td></tr>`;
  } else if (pagedUsers.length === 0) {
    currentPg = 1;
    renderTable(); return;
  } else {
    tbody.innerHTML = pagedUsers.map((u, i) => {
      const statusClass = 'status-' + u.status;
      const statusLabel = u.status.charAt(0).toUpperCase() + u.status.slice(1);
      const planClass = u.plan === 'Premium' ? 'plan-premium' : 'plan-free';
      const globalI = (currentPg - 1) * PAGE_SIZE + i;
      return `
        <tr>
          <td>
            <div class="user-cell">
              <div class="user-avatar" style="background:${u.color};">${u.initials}</div>
              <div><div class="user-full">${u.name}</div></div>
            </div>
          </td>
          <td class="email-cell">${u.email}</td>
          <td style="color:var(--text-muted);font-size:0.82rem;">${u.joined}</td>
          <td><span class="plan-badge ${planClass}">${u.plan}</span></td>
          <td>
            <div class="status-wrap">
              <div class="status-dot ${statusClass}"></div>
              ${statusLabel}
            </div>
          </td>
          <td class="last-active">${u.lastActive}</td>
          <td>
            <div class="actions-cell">
              <button class="action-btn btn-view" onclick="openView(${globalI})">👁 View</button>
              <button class="action-btn btn-edit" onclick="openEdit(${globalI})">✏ Edit</button>
              <button class="action-btn btn-block" onclick="openBlock(${globalI})">🚫 Block</button>
            </div>
          </td>
        </tr>`;
    }).join('');
  }
  const totalPages = Math.max(1, Math.ceil(filteredUsers.length / PAGE_SIZE));
  const start = (currentPg - 1) * PAGE_SIZE + 1;
  const end = Math.min(currentPg * PAGE_SIZE, filteredUsers.length);
  document.getElementById('pgInfo').textContent = `Showing ${start} to ${end} of 1,248 users`;
  renderPagination(totalPages);
}

function renderPagination(totalPages) {
  const container = document.querySelector('.page-controls');
  if (!container) return;
  let html = `<button class="pg-btn nav-pg" onclick="changePg(-1)">‹</button>`;
  const maxShow = 5;
  let pages = [];
  if (totalPages <= maxShow) {
    for (let i = 1; i <= totalPages; i++) pages.push(i);
  } else {
    pages = [1, 2, currentPg - 1, currentPg, currentPg + 1, totalPages - 1, totalPages];
    pages = [...new Set(pages)].filter(p => p >= 1 && p <= totalPages).sort((a,b) => a-b);
  }
  let prev = 0;
  pages.forEach(p => {
    if (prev && p - prev > 1) html += `<button class="pg-btn" disabled>…</button>`;
    html += `<button class="pg-btn${p === currentPg ? ' active-pg' : ''}" onclick="jumpPg(${p})">${p}</button>`;
    prev = p;
  });
  html += `<button class="pg-btn nav-pg" onclick="changePg(1)">›</button>`;
  container.innerHTML = html;
}

function changePg(dir) {
  const totalPages = Math.max(1, Math.ceil(filteredUsers.length / PAGE_SIZE));
  jumpPg(Math.max(1, Math.min(totalPages, currentPg + dir)));
}
function jumpPg(n) {
  currentPg = n;
  renderTable();
}
function updatePerPage(v) { showToast(`Showing ${v}`); }

