function renderTable() {
  const tbody = document.getElementById('userTableBody');
  if (filteredUsers.length === 0) {
    tbody.innerHTML = `<tr><td colspan="7" style="text-align:center;padding:3rem;color:var(--text-dim);">No users found</td></tr>`;
    return;
  }

  tbody.innerHTML = filteredUsers.map((u, i) => {
    const statusClass = 'status-' + u.status;
    const statusLabel = u.status.charAt(0).toUpperCase() + u.status.slice(1);
    const planClass = u.plan === 'Premium' ? 'plan-premium' : 'plan-free';
    return `
      <tr>
        <td>
          <div class="user-cell">
            <div class="user-avatar" style="background:${u.color};">${u.initials}</div>
            <div>
              <div class="user-full">${u.name}</div>
            </div>
          </div>
        </td>
        <td class="email-cell">${u.email}</td>
        <td style="color:var(--text-muted);font-size:0.82rem;">${u.joined}</td>
        <td><span class="plan-badge ${planClass}">${u.plan}</span></td>
        <td>
          <div class="status-cell ${statusClass}">
            <div class="status-dot"></div>
            ${statusLabel}
          </div>
        </td>
        <td class="last-active">${u.lastActive}</td>
        <td>
          <div class="actions-cell">
            <button class="action-btn btn-view" onclick="openView(${i})">👁 View</button>
            <button class="action-btn btn-edit" onclick="openEdit(${i})">✏ Edit</button>
            <button class="action-btn btn-block" onclick="openBlock(${i})">🚫 Block</button>
          </div>
        </td>
      </tr>`;
  }).join('');
}

function applyFilters() {
  const q = (document.getElementById('tableSearch').value || document.getElementById('topSearch').value || '').toLowerCase().trim();
  filteredUsers = users.filter(u => {
    const typeOk = currentTypeFilter === 'all' ||
      (currentTypeFilter === 'premium' && u.plan === 'Premium') ||
      (currentTypeFilter === 'free' && u.plan === 'Free');
    const statusOk = !currentStatusFilter || u.status === currentStatusFilter;
    const searchOk = !q || u.name.toLowerCase().includes(q) || u.email.toLowerCase().includes(q);
    return typeOk && statusOk && searchOk;
  });
  renderTable();
  document.getElementById('pgInfo').textContent = `Showing 1 to ${filteredUsers.length} of 1,248 users`;
}

